{
  "maturity": "Research/Development",
  "description": "The blog post discusses the development and evaluation of recommendation systems for grocery shopping at Picnic. It focuses on comparing a simple model (CARP) with more complex sequential recommendation models (e.g., SASRec, BERT4Rec, LightSANS, etc.) for both repeat and explore item recommendations. CARP, which is based on repeat purchase patterns, outperforms all other models in terms of performance for repeat items. However, the blog highlights the difficulty of recommending explore items (unbought products), where even complex models perform poorly. The authors also explore alternative approaches, such as recommending categories instead of individual items and extending the evaluation period to capture delayed purchases.",
  "ai_components": [
    {
      "name": "CARP (Customer Article Purchase Model)",
      "type": "Machine Learning Model",
      "description": "A simple model that leverages repeat purchase patterns to recommend items. It outperforms more complex models in terms of performance for repeat items."
    },
    {
      "name": "Sequential Recommendation Models",
      "type": "Machine Learning Models",
      "description": "A set of models (e.g., SASRec, BERT4Rec, LightSANS, etc.) that use sequential data to predict the next item or basket. These models are evaluated for their performance in both repeat and explore item recommendations."
    },
    {
      "name": "Next-Basket Recommendation Model",
      "type": "Machine Learning Model",
      "description": "An adaptation of sequential recommendation models to predict an entire basket of items rather than a single item. This approach is novel and shows better performance in capturing repeat-explore patterns."
    },
    {
      "name": "Category Recommendation Model",
      "type": "Machine Learning Model",
      "description": "A model that recommends categories of items instead of individual items. This approach reduces sparsity and improves performance compared to item-level recommendations."
    }
  ],
  "data_sources": [
    {
      "name": "Picnic Customer Item Interactions",
      "type": "Historical Data",
      "description": "A dataset containing customer purchase history within Picnic, used to train and evaluate the recommendation models."
    },
    {
      "name": "TaFeng Dataset",
      "type": "Public Dataset",
      "description": "A publicly available dataset used for benchmarking the recommendation models. It contains customer purchase data from a retail store."
    }
  ],
  "evaluation_metrics": [
    "HitRate@1",
    "Precision@5",
    "Precision@10",
    "MAP@30"
  ],
  "key_findings": [
    "CARP outperforms all benchmarked models in terms of performance for repeat items.",
    "The performance gap between repeat and explore items is significant, with repeat performance often 10x better than explore performance.",
    "Complex models like transformers do not necessarily outperform simpler models in this context.",
    "Category recommendations can reduce sparsity and improve performance compared to item-level recommendations.",
    "Extending the evaluation period to capture delayed purchases can improve model performance."
  ],
  "next_steps": [
    "Developing 'maybe you forgot these articles' and recipe recommendations.",
    "Exploring alternative approaches to improve explore item recommendations.",
    "Continuing research and development in recommendation systems for grocery shopping."
  ]
}

