{
  "model": "Client Item Recommendation Model",
  "description": "The Client Item Recommendation Model, known as CTSM (Client Temporal State Model), is a machine learning system developed by Stitch Fix to improve the accuracy and efficiency of item recommendations for clients. It replaces multiple region-, business line-, and channel-specific models with a single unified model that captures the dynamic nature of client preferences over time.",
  "key_components": {
    "client_state_modeling": {
      "description": "CTSM models the client's state as a dynamic entity that evolves over time, rather than treating it as static. This is achieved by encoding client events (e.g., profile updates, item interactions) into a temporal sequence and using a Temporally-Masked Encoder (TME) to process these events in a time-safe manner.",
      "features": [
        "Time-safe design: Ensures that past observations are not influenced by future events.",
        "Event-based updates: Client state is updated based on real-time interactions and profile changes.",
        "GRU-style gated updates: Combines the sequential processing of RNNs with the parallelization benefits of transformers."
      ]
    },
    "item_embedding": {
      "description": "Items are represented using an EmbeddingBag approach, where item features are summed to form a fixed-dimensional embedding. This embedding is used consistently across all contexts and is not transformed for different prediction tasks.",
      "features": [
        "Consistent item representation: Same embedding used across all platforms and prediction tasks.",
        "Simplified feature engineering: Raw or minimally processed features are used directly."
      ]
    },
    "temporally_masked_encoder_with_gated_updates": {
      "description": "The TME with gated updates is a key architectural component of CTSM. It processes client events in a time-aware manner, using a masked attention mechanism to compute a weighted sum of past events. The gated update mechanism allows the model to selectively update the client's hidden state based on new information.",
      "features": [
        "Efficient computation: Processes updates in parallel within subsequences.",
        "Modular design: Each target (e.g., Fix purchase, Freestyle interaction) is handled as a separate component.",
        "Instant reflection of updates: Recent client interactions are immediately reflected in recommendations."
      ]
    },
    "event_modeling": {
      "description": "CTSM distinguishes between two types of events: Updates and Targets. Updates are observations that change the client's state, while Targets are outcomes that the model aims to predict.",
      "features": [
        "Update events: Include profile changes, Fix checkouts, and other client interactions.",
        "Target events: Include purchase outcomes, client satisfaction, and other business KPIs.",
        "Loss functions: Each target is associated with a loss function (e.g., binary cross-entropy) to measure prediction accuracy."
      ]
    }
  },
  "deployment": {
    "description": "CTSM has been fully productionized and is used across all business lines (Womens, Mens, Kids), regions (US, UK), and shopping experiences (Fix, Freestyle). It has replaced multiple region- and channel-specific models with a single, unified model.",
    "features": [
      "A/B testing: CTSM was tested against predecessor models across all business lines and regions before full deployment.",
      "Resource efficiency: Reduced training and inference costs by consolidating multiple models into one.",
      "Lower maintenance: Simplified model architecture and feature pipeline reduce maintenance overhead.",
      "Accelerated development: Modular design allows for rapid iteration and improvement of specific components."
    ]
  },
  "performance_impact": {
    "description": "CTSM has delivered significant improvements in key performance metrics across all business lines and regions.",
    "metrics": {
      "key_performance_indices": [
        "Revenue: Increased revenue through more accurate and relevant recommendations.",
        "Retention: Improved client retention by better aligning recommendations with client preferences.",
        "Client satisfaction: Higher client satisfaction due to more personalized and timely recommendations."
      ],
      "computing_resources": [
        "Reduced training costs: Only one model is trained, rather than multiple region- and channel-specific models.",
        "Lower inference costs: A single inference endpoint consumes fewer resources than multiple endpoints."
      ],
      "maintenance": [
        "Simplified model architecture: Only one repository, training pipeline, and endpoint need to be maintained.",
        "Reduced preprocessing: Minimal feature engineering is required, reducing the need for complex preprocessing jobs."
      ],
      "development_velocity": [
        "Faster iteration: Modular design allows for rapid development and testing of new features.",
        "Improved subsampling techniques: Recent improvements in Freestyle target logic were implemented quickly and efficiently."
      ]
    }
  },
  "conclusion": {
    "description": "CTSM represents a major advancement in Stitch Fix's recommendation system. By modeling client state as a dynamic entity and using a time-safe, modular architecture, CTSM delivers more accurate and relevant recommendations while reducing computational costs and maintenance overhead. The model's success has enabled the team to accelerate development and continue improving the client experience at an unprecedented pace."
  }
}

{
  "ai_system_description": {
    "system_name": "Trust and Safety Prevalence Radar",
    "purpose": "To continuously measure and monitor platform safety by estimating the prevalence of policy-violating content across different policy areas, surfaces, and segments using AI-assisted sampling and labeling.",
    "key_components": [
      {
        "component_name": "Sampling Module",
        "description": "Samples images from the daily user impressions stream using risk scores from production enforcement models to improve sampling efficiency. Missing scores are imputed with the day's median to ensure fresh content is included."
      },
      {
        "component_name": "Labeling Module",
        "description": "Bulk-labels the sampled content using a multimodal LLM (vision + text) with prompts reviewed by policy SMEs. The system logs decisions, rationales, and lineage for auditability."
      },
      {
        "component_name": "Estimation Module",
        "description": "Computes overall prevalence and pivots, persisting estimates, weights, and labels to production stores. Uses inverse-probability weighting to maintain unbiased estimates."
      },
      {
        "component_name": "Dashboard and Alerting System",
        "description": "Provides daily prevalence with 95% CI, sample positive rate, auxiliary score distributions, and run health/lineage. Allows slicing by policy area, surface, and sub-policy."
      }
    ],
    "data_flow": [
      {
        "step": "Input Data Collection",
        "description": "Collects engagement data at the entity × day level (e.g., impressions, Pin clicks, hides, reports) and the latest production risk scores."
      },
      {
        "step": "Sampling",
        "description": "Uses a weighted reservoir sampler to give more chances to items with higher impressions and higher risk scores, preserving unbiased estimates."
      },
      {
        "step": "Labeling",
        "description": "The LLM returns policy-defined labels (e.g., {safe, not_safe, unsure}) and records token usage and per-run cost for budgeting."
      },
      {
        "step": "Estimation",
        "description": "Computes prevalence estimates, persists data to production stores, and writes diagnostics/lineage for audits."
      },
      {
        "step": "Dashboard and Alerting",
        "description": "Displays prevalence metrics, 95% CI, and other diagnostics. Supports slicing by policy area, surface, and sub-policy."
      }
    ],
    "ai_models_used": [
      {
        "model_name": "Multimodal LLM",
        "description": "Used for bulk-labeling sampled content. The model is vision + text and uses prompts reviewed by policy SMEs. It logs decisions, rationales, and lineage for auditability."
      }
    ],
    "impact": {
      "proactive_risk_detection": "Enables real-time monitoring and faster root cause analysis when issues emerge.",
      "product_iteration": "Provides immediate insight into how product launches impact platform trust and safety, enabling faster course correction.",
      "strategic_decision_making": [
        "Benchmarking and goal setting for platform health",
        "Cross-team alignment around shared metrics",
        "Data-driven resource allocation",
        "Precise intervention measurement with statistical confidence"
      ]
    },
    "constraints_and_tradeoffs": [
      "Rare categories can have wide daily CIs, requiring adaptive sampling strategies.",
      "Policy/prompt drift is managed through versioning and label backfills.",
      "LLM decision quality stability is critical for metric conviction, requiring regular validation.",
      "Cost guardrails are in place to track token usage and per-run costs."
    ],
    "future_focus": [
      "Expand pivoting ability to viewer country, age, etc.",
      "Cost optimization through multi-step LLM labeling and fine-tuning.",
      "Human-in-the-loop denoising/debiasing to minimize LLM-human bias.",
      "Generalizing the pipeline for company-wide measurement applications."
    ]
  }
}

