        "description": "Generated when the decision engine requests a tool to be executed, triggering the tool dispatcher."
      },
      {
        "name": "Tool Call Output Event",
        "description": "Produced when the tool dispatcher completes a tool execution, triggering the decision engine to process the output."
      },
